class Solution:
    def compareBitonicSums(self, nums):
        lo, hi = 0, len(nums) - 1
        while lo < hi:
            mid = (lo + hi) // 2
            if nums[mid] < nums[mid + 1]:
                lo = mid + 1
            else:
                hi = mid
        peak = lo
        asc = sum(nums[:peak + 1])
        desc = sum(nums[peak:])
        if asc > desc:
            return 0
        if desc > asc:
            return 1
        return -1

