class Solution:
    def compareBitonicSums(self, nums: list[int]) -> int:
        peak = nums.index(max(nums))
        asc_sum = sum(nums[:peak + 1])
        desc_sum = sum(nums[peak:])
        if asc_sum > desc_sum:
            return 0
        if desc_sum > asc_sum:
            return 1
        return -1

