var compareBitonicSums = function(nums) {
    let peak = 0;
    for (let i = 1; i < nums.length; i++) {
        if (nums[i] > nums[peak]) peak = i;
    }
    let asc = 0;
    for (let i = 0; i <= peak; i++) asc += nums[i];
    let desc = 0;
    for (let i = peak; i < nums.length; i++) desc += nums[i];
    if (asc > desc) return 0;
    if (desc > asc) return 1;
    return -1;
};
